#!/usr/bin/env python3"""NICTO ù Zip kaggle_data/ for Colab / Google Drive upload."""import os, shutil, tarfile, sysDATA_DIR = os.path.join(os.path.dirname(__file__), "..", "kaggle_data")OUTPUT = os.path.join(os.path.dirname(__file__), "..", "kaggle_data.tar.gz")def main():    if not os.path.isdir(DATA_DIR):        print(f"ERROR: {DATA_DIR} not found")        sys.exit(1)    print(f"Archiving {DATA_DIR} -> {OUTPUT} ...")    with tarfile.open(OUTPUT, "w:gz") as tar:        tar.add(DATA_DIR, arcname="kaggle_data")    size_mb = os.path.getsize(OUTPUT) / 1024 / 1024    print(f"Done: {OUTPUT} ({size_mb:.1f} MB)")    print()    print("=== Upload to Google Drive ===")    print("1. Upload kaggle_data.tar.gz to Google Drive")    print("2. In Colab notebook, run:")    print("   from google.colab import drive")    print("   drive.mount('/content/drive')")    print("   !tar -xzf /content/drive/MyDrive/kaggle_data.tar.gz -C /content/")    print()    print("=== Alternative: GitHub Release ===")    print("   gh release create data kaggle_data.tar.gz --title 'Training Data' --notes 'NICTO 4-model training data'")    print()    print("=== Alternative: Direct Download URL ===")    print("   !wget -q <url>/kaggle_data.tar.gz && tar -xzf kaggle_data.tar.gz")if __name__ == "__main__":    main()